import sys

class ListNode:
    __slots__ = ('val', 'next')
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def addTwoNumbers(self, l1: ListNode, l2: ListNode) -> ListNode:
        dummy = ListNode(0)
        cur = dummy
        carry = 0
        while l1 or l2 or carry:
            v1 = l1.val if l1 else 0
            v2 = l2.val if l2 else 0
            total = v1 + v2 + carry
            carry = total // 10
            cur.next = ListNode(total % 10)
            cur = cur.next
            if l1:
                l1 = l1.next
            if l2:
                l2 = l2.next
        return dummy.next

def build_list(vals):
    dummy = ListNode(0)
    cur = dummy
    for v in vals:
        cur.next = ListNode(v)
        cur = cur.next
    return dummy.next

def list_to_output(node):
    out = []
    while node:
        out.append(str(node.val))
        node = node.next
    return ' '.join(out)

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    try:
        n1 = int(next(it))
        vals1 = [int(next(it)) for _ in range(n1)]
        n2 = int(next(it))
        vals2 = [int(next(it)) for _ in range(n2)]
    except StopIteration:
        sys.exit(0)
    l1 = build_list(vals1)
    l2 = build_list(vals2)
    sol = Solution()
    res = sol.addTwoNumbers(l1, l2)
    print(list_to_output(res))

