#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {
        ListNode dummy(0);
        ListNode* cur = &dummy;
        int carry = 0;
        while (l1 || l2 || carry) {
            int v1 = l1 ? l1->val : 0;
            int v2 = l2 ? l2->val : 0;
            int sum = v1 + v2 + carry;
            carry = sum / 10;
            cur->next = new ListNode(sum % 10);
            cur = cur->next;
            if (l1) l1 = l1->next;
            if (l2) l2 = l2->next;
        }
        return dummy.next;
    }
};

ListNode* buildList(const vector<int>& vals) {
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int v : vals) {
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    return dummy.next;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n1;
    if (!(cin >> n1)) return 0;
    vector<int> vals1(n1);
    for (int i = 0; i < n1; ++i) cin >> vals1[i];
    int n2;
    if (!(cin >> n2)) return 0;
    vector<int> vals2(n2);
    for (int i = 0; i < n2; ++i) cin >> vals2[i];
    ListNode* l1 = buildList(vals1);
    ListNode* l2 = buildList(vals2);
    Solution sol;
    ListNode* res = sol.addTwoNumbers(l1, l2);
    bool first = true;
    while (res) {
        if (!first) cout << ' ';
        cout << res->val;
        first = false;
        ListNode* tmp = res;
        res = res->next;
        delete tmp; // free memory
    }
    cout << "\n";
    // free remaining input lists
    while (l1) { ListNode* tmp = l1; l1 = l1->next; delete tmp; }
    while (l2) { ListNode* tmp = l2; l2 = l2->next; delete tmp; }
    return 0;
}
